   203→        if (debugMode == RoutingAllocation.DebugMode.OFF) {
   204→            var result = Decision.YES;
   205→            for (AllocationDecider decider : deciders) {
   206→                var decision = deciderAction.apply(decider);
   207→                if (decision.type() == Decision.Type.NO) {
   208→                    if (logger.isTraceEnabled()) {
   209→                        logger.trace(() -> logMessageCreator.apply(decider.getClass().getSimpleName(), decision));
   210→                    }
   211→                    return decision;
   212→                } else if (result.type() == Decision.Type.YES && decision.type() == Decision.Type.THROTTLE) {
   213→                    result = decision;
   214→                }
   215→            }
   216→            return result;
   217→        } else {
   218→            var result = new Decision.Multi();
   219→            for (AllocationDecider decider : deciders) {
   220→                var decision = deciderAction.apply(decider);
   221→                if (logger.isTraceEnabled() && decision.type() == Decision.Type.NO) {
   222→                    logger.trace(() -> logMessageCreator.apply(decider.getClass().getSimpleName(), decision));
   223→                }
   224→                if (decision != Decision.ALWAYS && (debugMode == RoutingAllocation.DebugMode.ON || decision.type() != Decision.Type.YES)) {
   225→                    result.add(decision);
   226→                }
   227→            }
   228→            return result;
   229→        }
   230→    }
   231→
   232→    public Optional<Set<String>> getForcedInitialShardAllocationToNodes(ShardRouting shardRouting, RoutingAllocation allocation) {
   233→        var result = Optional.<Set<String>>empty();
   234→        for (AllocationDecider decider : deciders) {
   235→            var forcedInitialNodeIds = decider.getForcedInitialShardAllocationToNodes(shardRouting, allocation);
   236→            if (forcedInitialNodeIds.isPresent()) {
   237→                result = result.map(nodeIds -> Sets.intersection(nodeIds, forcedInitialNodeIds.get())).or(() -> forcedInitialNodeIds);
   238→            }
   239→        }
   240→        return result;
   241→    }
