    21→/**
    22→ * <p>
    23→ * A {@link ShardsAllocator} is the main entry point for shard allocation on nodes in the cluster.
    24→ * The allocator makes basic decision where a shard instance will be allocated, if already allocated instances
    25→ * need to relocate to other nodes due to node failures or due to rebalancing decisions.
    26→ * </p>
    27→ */
    28→public interface ShardsAllocator {
    29→
    30→    /**
    31→     * Allocates shards to nodes in the cluster. An implementation of this method should:
    32→     * - assign unassigned shards
    33→     * - relocate shards that cannot stay on a node anymore
    34→     * - relocate shards to find a good shard balance in the cluster
    35→     *
    36→     * @param allocation current node allocation
    37→     */
    38→    void allocate(RoutingAllocation allocation);
    39→
    40→    /**
    41→     * Allocates shards to nodes in the cluster. An implementation of this method should:
    42→     * - assign unassigned shards
    43→     * - relocate shards that cannot stay on a node anymore
    44→     * - relocate shards to find a good shard balance in the cluster
    45→     *
    46→     * @param allocation current node allocation
    47→     * @param listener listener to be executed once async allocation is completed
    48→     */
    49→    default void allocate(RoutingAllocation allocation, ActionListener<Void> listener) {
    50→        allocate(allocation);
    51→        listener.onResponse(null);
    52→    }
    53→
    54→    /**
    55→     * Execute allocation commands
    56→     */
    57→    default RoutingExplanations execute(RoutingAllocation allocation, AllocationCommands commands, boolean explain, boolean retryFailed) {
    58→        var originalDebugMode = allocation.getDebugMode();
    59→        allocation.debugDecision(true);
    60→        // we ignore disable allocation, because commands are explicit
    61→        allocation.ignoreDisable(true);
    62→
    63→        try {
    64→            if (retryFailed) {
    65→                allocation.routingNodes().resetFailedCounter(allocation.changes());
    66→            }
    67→            return commands.execute(allocation, explain);
    68→        } finally {
    69→            // revert the ignore disable flag, since when rerouting, we want the original setting to take place
    70→            allocation.ignoreDisable(false);
    71→            allocation.setDebugMode(originalDebugMode);
    72→        }
    73→    }
    74→
    75→    /**
    76→     * Returns the decision for where a shard should reside in the cluster.  If the shard is unassigned,
    77→     * then the {@link AllocateUnassignedDecision} will be non-null.  If the shard is not in the unassigned
    78→     * state, then the {@link MoveDecision} will be non-null.
    79→     *
    80→     * This method is primarily used by the cluster allocation explain API to provide detailed explanations
    81→     * for the allocation of a single shard.  Implementations of the {@link #allocate(RoutingAllocation)} method
    82→     * may use the results of this method implementation to decide on allocating shards in the routing table
    83→     * to the cluster.
    84→     *
    85→     * If an implementation of this interface does not support explaining decisions for a single shard through
    86→     * the cluster explain API, then this method should throw a {@code UnsupportedOperationException}.
    87→     */
    88→    ShardAllocationDecision decideShardAllocation(ShardRouting shard, RoutingAllocation allocation);
    89→}
