package org.elasticsearch.cluster.routing.allocation.allocator;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.node.DiscoveryNode;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.AllocateUnassignedDecision;
import org.elasticsearch.cluster.routing.allocation.MoveDecision;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.ShardAllocationDecision;
import org.elasticsearch.cluster.routing.allocation.WriteLoadForecaster;
import org.elasticsearch.cluster.routing.allocation.decider.AllocationDeciders;
import org.elasticsearch.cluster.routing.allocation.decider.Decision;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.injection.guice.Inject;

import java.util.List;
import java.util.Locale;
import java.util.Map;

/**
 * A {@link ShardsAllocator} that extends {@link BalancedShardsAllocator} with priority-tier awareness.
 *
 * <p>Each index may declare a desired tier via the {@code index.routing.allocation.priority} setting
 * (values: {@code hot}, {@code warm}, {@code cold}, {@code frozen}). Each node advertises its tier
 * via a node attribute (default attribute name: {@code tier}).
 *
 * <p>This allocator applies a configurable priority bias to the weight function so that higher-tier
 * nodes are preferred for high-priority indices. The actual hard/soft enforcement of tier constraints
 * is delegated to {@link org.elasticsearch.cluster.routing.allocation.decider.PriorityAllocationDecider},
 * which must be included in the {@link AllocationDeciders} collection passed to this allocator.
 *
 * <p>Interaction with existing deciders:
 * <ul>
 *   <li>{@code DiskThresholdDecider} — disk watermarks are always respected; priority does not
 *       override them.</li>
 *   <li>{@code AwarenessAllocationDecider} — rack/zone awareness applies independently; both
 *       constraints must be satisfied simultaneously.</li>
 *   <li>{@code FilterAllocationDecider} — explicit include/exclude/require filters take precedence
 *       over tier preference.</li>
 *   <li>{@code ThrottlingAllocationDecider} — concurrent recovery limits are not bypassed.</li>
 * </ul>
 */
public class PriorityShardsAllocator extends BalancedShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    // -------------------------------------------------------------------------
    // Index-level settings
    // -------------------------------------------------------------------------

    /**
     * Per-index setting declaring the desired allocation tier.
     * Accepted values: {@code hot}, {@code warm}, {@code cold}, {@code frozen}.
     * Defaults to {@code hot}.
     */
    public static final Setting<String> INDEX_ROUTING_PRIORITY_SETTING = new Setting<>(
        "index.routing.allocation.priority",
        "hot",
        value -> {
            try {
                Tier.fromString(value);
            } catch (IllegalArgumentException e) {
                throw new IllegalArgumentException(
                    "invalid value [" + value + "] for [index.routing.allocation.priority]; "
                        + "must be one of [hot, warm, cold, frozen]"
                );
            }
            return value;
        },
        Property.Dynamic,
        Property.IndexScope
    );

    /**
     * Per-index flag. When {@code true}, shards are never placed on a node whose tier is below
     * the index's required tier (hard constraint). When {@code false} (default), the tier
     * preference is a soft constraint — placement on a lower-tier node is allowed if no
     * higher-tier node passes all other deciders.
     */
    public static final Setting<Boolean> INDEX_ROUTING_PRIORITY_STRICT_SETTING = Setting.boolSetting(
        "index.routing.allocation.priority.strict",
        false,
        Property.Dynamic,
        Property.IndexScope
    );

    // -------------------------------------------------------------------------
    // Cluster-level settings
    // -------------------------------------------------------------------------

    /**
     * Controls how strongly the priority bias overrides normal balance scoring.
     * A value of {@code 0.0} disables the bias entirely (the decider still enforces soft/hard
     * constraints). Higher values cause tier preference to dominate over balance.
     */
    public static final Setting<Float> PRIORITY_WEIGHT_SETTING = Setting.floatSetting(
        "cluster.routing.allocation.priority.weight",
        5.0f,
        0.0f,
        Property.Dynamic,
        Property.NodeScope
    );

    /**
     * The node attribute name that carries the tier label (e.g., {@code node.attr.tier: hot}).
     * Not dynamic; requires a rolling restart to change.
     */
    public static final Setting<String> PRIORITY_ATTRIBUTE_SETTING = Setting.simpleString(
        "cluster.routing.allocation.priority.attribute",
        "tier",
        Property.NodeScope
    );

    // -------------------------------------------------------------------------
    // Internal state
    // -------------------------------------------------------------------------

    /** Bias subtracted from the weight score when a node's tier matches the index's required tier. */
    private volatile float priorityWeight;

    /** Node attribute name used to look up the tier of each node. */
    private final String tierAttribute;

    // -------------------------------------------------------------------------
    // Constructors
    // -------------------------------------------------------------------------

    @Inject
    public PriorityShardsAllocator(ClusterSettings clusterSettings, WriteLoadForecaster writeLoadForecaster) {
        super(clusterSettings, writeLoadForecaster);
        this.tierAttribute = PRIORITY_ATTRIBUTE_SETTING.get(clusterSettings.getSettings());
        clusterSettings.initializeAndWatch(PRIORITY_WEIGHT_SETTING, value -> this.priorityWeight = value);
    }

    // -------------------------------------------------------------------------
    // ShardsAllocator overrides
    // -------------------------------------------------------------------------

    /**
     * Allocates unassigned shards and rebalances the cluster with priority-tier awareness.
     *
     * <p>The parent {@link BalancedShardsAllocator} drives the three allocation passes
     * (allocateUnassigned → moveShards → balance). This class influences node selection
     * within those passes via {@link #adjustedWeight}.
     */
    @Override
    public void allocate(RoutingAllocation allocation) {
        logger.debug("PriorityShardsAllocator.allocate: starting priority-aware allocation pass");
        super.allocate(allocation);
    }

    /**
     * {@inheritDoc}
     *
     * <p>Delegates to the parent and surfaces tier-related decisions for the explain API.
     */
    @Override
    public ShardAllocationDecision decideShardAllocation(ShardRouting shard, RoutingAllocation allocation) {
        return super.decideShardAllocation(shard, allocation);
    }

    // -------------------------------------------------------------------------
    // Priority-aware weight calculation
    // -------------------------------------------------------------------------

    /**
     * Returns an adjusted weight for {@code node} when considering placement of a shard
     * belonging to {@code indexMetadata}. A lower adjusted weight means the node is more
     * preferred.
     *
     * <p>The adjustment subtracts {@link #priorityWeight} when the node's tier is greater
     * than or equal to the index's required tier, making such nodes more attractive to the
     * balancer's greedy selection.
     *
     * @param baseWeight    the raw weight produced by {@link BalancedShardsAllocator}'s weight function
     * @param node          the candidate routing node
     * @param indexMetadata metadata of the index whose shard is being placed
     * @return              the priority-adjusted weight
     */
    public float adjustedWeight(float baseWeight, RoutingNode node, IndexMetadata indexMetadata) {
        if (priorityWeight == 0.0f) {
            return baseWeight;
        }
        Tier requiredTier = requiredTierForIndex(indexMetadata);
        Tier nodeTier = tierForNode(node.node());
        if (nodeTier != null && nodeTier.level >= requiredTier.level) {
            return baseWeight - priorityWeight;
        }
        return baseWeight;
    }

    // -------------------------------------------------------------------------
    // Helper methods
    // -------------------------------------------------------------------------

    /**
     * Reads the required {@link Tier} for an index from {@link #INDEX_ROUTING_PRIORITY_SETTING}.
     * Defaults to {@link Tier#HOT} if the setting is absent or unrecognised.
     */
    Tier requiredTierForIndex(IndexMetadata indexMetadata) {
        String raw = INDEX_ROUTING_PRIORITY_SETTING.get(indexMetadata.getSettings());
        try {
            return Tier.fromString(raw);
        } catch (IllegalArgumentException e) {
            logger.warn("unrecognised priority tier [{}] for index [{}], defaulting to hot", raw, indexMetadata.getIndex().getName());
            return Tier.HOT;
        }
    }

    /**
     * Reads the {@link Tier} for a node from its attributes using {@link #tierAttribute}.
     * Returns {@code null} if the node has no tier attribute (untiered — always eligible).
     */
    Tier tierForNode(DiscoveryNode node) {
        String raw = node.getAttributes().get(tierAttribute);
        if (raw == null) {
            return null;
        }
        try {
            return Tier.fromString(raw);
        } catch (IllegalArgumentException e) {
            logger.warn("node [{}] has unrecognised tier attribute value [{}]", node.getId(), raw);
            return null;
        }
    }

    // -------------------------------------------------------------------------
    // Tier enum
    // -------------------------------------------------------------------------

    /**
     * Represents a node/index priority tier.
     *
     * <p>Tiers are ordered by {@link #level}: higher level means higher priority (faster hardware).
     * The ordering is used both by this allocator (weight bias) and by
     * {@link org.elasticsearch.cluster.routing.allocation.decider.PriorityAllocationDecider}
     * (canAllocate/canRemain decisions).
     */
    public enum Tier {
        FROZEN(0),
        COLD(1),
        WARM(2),
        HOT(3);

        /** Numeric level; higher == more preferred. */
        public final int level;

        Tier(int level) {
            this.level = level;
        }

        /**
         * Case-insensitive parse from a string value.
         *
         * @throws IllegalArgumentException if the value is not a recognised tier name
         */
        public static Tier fromString(String value) {
            return switch (value.toLowerCase(Locale.ROOT)) {
                case "hot" -> HOT;
                case "warm" -> WARM;
                case "cold" -> COLD;
                case "frozen" -> FROZEN;
                default -> throw new IllegalArgumentException("unknown tier: " + value);
            };
        }

        @Override
        public String toString() {
            return name().toLowerCase(Locale.ROOT);
        }
    }
}

