package org.elasticsearch.cluster.routing.allocation.decider;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.allocator.PriorityShardsAllocator;
import org.elasticsearch.cluster.routing.allocation.allocator.PriorityShardsAllocator.Tier;
import org.elasticsearch.common.settings.ClusterSettings;

/**
 * An {@link AllocationDecider} that enforces tier-based placement constraints derived from
 * {@link PriorityShardsAllocator#INDEX_ROUTING_PRIORITY_SETTING}.
 *
 * <p>For each candidate (shard, node) pair this decider compares the index's required tier
 * against the node's advertised tier (via the configurable node attribute, default {@code tier}):
 *
 * <ul>
 *   <li>If the node has no tier attribute, the shard is always allowed (backwards-compatible
 *       behaviour for untiered clusters).</li>
 *   <li>If the node's tier is at or above the required tier, the decision is {@link Decision#YES}.</li>
 *   <li>If the node's tier is below the required tier:
 *     <ul>
 *       <li>In <em>soft</em> mode ({@code index.routing.allocation.priority.strict: false},
 *           default) the decision is {@link Decision#THROTTLE}, signalling a preference
 *           against this node but allowing fall-back placement if no better node exists.</li>
 *       <li>In <em>hard</em> mode ({@code index.routing.allocation.priority.strict: true})
 *           the decision is {@link Decision#NO}, preventing placement on under-tier nodes
 *           entirely.</li>
 *     </ul>
 *   </li>
 * </ul>
 *
 * <p>This decider composes safely with all existing deciders ({@code DiskThresholdDecider},
 * {@code AwarenessAllocationDecider}, etc.) because it runs inside the standard
 * {@link AllocationDeciders} pipeline, which short-circuits on the first {@link Decision#NO}.
 *
 * <p>To register this decider, add it to the list returned by {@code ClusterModule#createAllocationDeciders}.
 */
public class PriorityAllocationDecider extends AllocationDecider {

    private static final Logger logger = LogManager.getLogger(PriorityAllocationDecider.class);

    /** Label used in explain API responses and log messages. */
    public static final String NAME = "priority";

    /** Node attribute key used to look up the tier label. Sourced from cluster settings. */
    private final String tierAttribute;

    /**
     * Constructs the decider, reading the configured tier attribute name from cluster settings.
     * This value is static per node and not watched for dynamic changes (requires a restart).
     */
    public PriorityAllocationDecider(ClusterSettings clusterSettings) {
        this.tierAttribute = PriorityShardsAllocator.PRIORITY_ATTRIBUTE_SETTING.get(clusterSettings.getSettings());
    }

    // -------------------------------------------------------------------------
    // AllocationDecider overrides
    // -------------------------------------------------------------------------

    /**
     * Returns whether the given shard can be allocated to the given node, considering tier
     * compatibility.
     *
     * <p>Called once per (shard, candidate-node) pair during both initial assignment and
     * rebalancing.
     */
    @Override
    public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
        IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shardRouting.index());
        return tierDecision(indexMetadata, node, allocation);
    }

    /**
     * Returns whether the given shard can remain on its current node.
     *
     * <p>A shard must move if its node's tier has dropped below the index's required tier
     * and the index is in strict mode. In soft mode the shard is allowed to remain (avoiding
     * churn), but the allocator will prefer to relocate it when a better node is available.
     */
    @Override
    public Decision canRemain(IndexMetadata indexMetadata, ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
        return tierDecision(indexMetadata, node, allocation);
    }

    // -------------------------------------------------------------------------
    // Core decision logic
    // -------------------------------------------------------------------------

    /**
     * Computes the tier-compatibility decision for placing a shard from {@code indexMetadata}
     * on {@code node}.
     */
    private Decision tierDecision(IndexMetadata indexMetadata, RoutingNode node, RoutingAllocation allocation) {
        String nodeTierValue = node.node().getAttributes().get(tierAttribute);

        // Untiered node: always eligible (backwards-compatible).
        if (nodeTierValue == null) {
            return allocation.decision(
                Decision.YES,
                NAME,
                "node [%s] has no [%s] attribute; eligible for any priority tier",
                node.nodeId(),
                tierAttribute
            );
        }

        Tier nodeTier;
        try {
            nodeTier = Tier.fromString(nodeTierValue);
        } catch (IllegalArgumentException e) {
            logger.warn("node [{}] has unrecognised tier attribute [{}]; treating as untiered", node.nodeId(), nodeTierValue);
            return allocation.decision(Decision.YES, NAME, "unrecognised tier attribute [%s] on node [%s]", nodeTierValue, node.nodeId());
        }

        Tier requiredTier;
        try {
            requiredTier = Tier.fromString(PriorityShardsAllocator.INDEX_ROUTING_PRIORITY_SETTING.get(indexMetadata.getSettings()));
        } catch (IllegalArgumentException e) {
            // Malformed setting — treat as no-preference to avoid blocking allocation.
            logger.warn("index [{}] has invalid priority tier setting; skipping tier check", indexMetadata.getIndex().getName());
            return allocation.decision(Decision.YES, NAME, "invalid priority tier setting on index [%s]", indexMetadata.getIndex().getName());
        }

        if (nodeTier.level >= requiredTier.level) {
            return allocation.decision(
                Decision.YES,
                NAME,
                "node tier [%s] meets or exceeds required tier [%s] for index [%s]",
                nodeTier,
                requiredTier,
                indexMetadata.getIndex().getName()
            );
        }

        // Node tier is below required. Apply soft or hard constraint.
        boolean strict = PriorityShardsAllocator.INDEX_ROUTING_PRIORITY_STRICT_SETTING.get(indexMetadata.getSettings());
        if (strict) {
            return allocation.decision(
                Decision.NO,
                NAME,
                "node tier [%s] is below required tier [%s] for index [%s] (strict mode)",
                nodeTier,
                requiredTier,
                indexMetadata.getIndex().getName()
            );
        } else {
            return allocation.decision(
                Decision.THROTTLE,
                NAME,
                "node tier [%s] is below required tier [%s] for index [%s]; preferred but not required",
                nodeTier,
                requiredTier,
                indexMetadata.getIndex().getName()
            );
        }
    }
}

